import { stdout } from "process";
import { AgentConfig } from "./agent-config.js";
import {
  pruneContext,
  truncateForContext,
  truncateForDisplay,
} from "./context-management.js";
import { logger } from "./logger.js";
import { Message, ToolMessage } from "./message.js";
import { LLMProvider, LLMResponse } from "./providers/llm-provider.js";

type RunnerConstructorProps = {
  llmProvider: LLMProvider;
  agentConfig: AgentConfig;
  maxSteps?: number;
  maxContextTokens?: number;
  signal?: AbortSignal;
  /** Si se provee, las invocaciones a la tool `ask_user` pausan el runner
   * y llaman a este callback. La respuesta se inyecta como tool_result. */
  onAskUser?: (question: string) => Promise<string>;
};

type RunnerEvent =
  | { type: "text"; text: string }
  | { type: "text_stream"; text: string }
  | { type: "text_stream_end" }
  | { type: "state"; message: Message }
  | { type: "tool_use"; name: string; input: unknown }
  | {
      type: "tool_result";
      output: string;
      /** Output completo (sin truncar) para poder mostrar un resumen real. */
      rawOutput?: string;
    }
  | { type: "ask_user"; question: string; toolId: string };

/** Estado mutable que comparten los métodos de un turno del loop. */
interface TurnState {
  textParts: string[];
  toolBlocks: Array<{ id: string; name: string; input: unknown }>;
  toolResults: ToolMessage[];
  stopReason: "end_turn" | "tool_use" | "max_tokens";
}

class Runner {
  // Métricas de una sola corrida (se resetean con resetMetrics()).
  // El acumulado histórico lo mantiene Session (addUsage), que es el
  // único dueño persistente del costo total.
  #llmProvider: LLMProvider;
  #agentConfig: AgentConfig;
  #maxSteps: number;
  #maxContextTokens: number;
  #signal: AbortSignal | undefined;
  #interrupted: boolean;
  #onAskUser: ((question: string) => Promise<string>) | undefined;
  #metrics: {
    totalInputTokens: number;
    totalOutputTokens: number;
    totalToolCalls: number;
    totalCost: number;
    startTime: number;
  };

  constructor({
    llmProvider,
    agentConfig,
    maxSteps = 15,
    maxContextTokens = 100_000,
    signal,
    onAskUser,
  }: RunnerConstructorProps) {
    this.#llmProvider = llmProvider;
    this.#agentConfig = agentConfig;
    this.#maxSteps = maxSteps;
    this.#maxContextTokens = maxContextTokens;
    this.#signal = signal;
    this.#interrupted = false;
    this.#onAskUser = onAskUser;
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }

  /** Expone si el runner fue interrumpido (SIGINT) — el caller lo usa para
   * saber si debe guardar métricas parciales o descartarlas. */
  get interrupted(): boolean {
    return this.#interrupted;
  }

  // ── helpers ────────────────────────────────────────────────────────

  /**
   * Arma el contenido del mensaje assistant a partir de lo producido
   * en el turno. Si no hay nada visible, pone un fallback.
   */
  #buildAssistantContent(state: TurnState): Message["content"] {
    const content: Message["content"] = [];
    if (state.textParts.length > 0) {
      content.push({ type: "text", text: state.textParts.join("") });
    }
    for (const tb of state.toolBlocks) {
      content.push({
        type: "tool_use",
        id: tb.id,
        name: tb.name,
        input: tb.input,
      });
    }
    if (content.length === 0) {
      content.push({
        type: "text",
        text: "(El modelo no produjo contenido visible en este turno)",
      });
    }
    return content;
  }

  /** Construye el snapshot del estado vacío para un turno nuevo. */
  #newTurnState(): TurnState {
    return {
      textParts: [],
      toolBlocks: [],
      toolResults: [],
      stopReason: "end_turn",
    };
  }

  // ── fases del turno ────────────────────────────────────────────────

  /** Llama al LLM (stream o no-stream), emite eventos y llena `state`. */
  async *#callLLM(
    prunedContext: Message[],
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const hasStream = typeof this.#llmProvider.callStream === "function";

    if (hasStream) {
      const stream = this.#llmProvider.callStream(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      for await (const event of stream) {
        if (event.type === "text") {
          state.textParts.push(event.text);
          yield { type: "text_stream", text: event.text };
        } else if (event.type === "tool_use") {
          state.toolBlocks.push({
            id: event.id,
            name: event.name,
            input: event.input,
          });
        } else if (event.type === "done") {
          state.stopReason = event.stop_reason;
          this.#metrics.totalInputTokens += event.usage.input_tokens;
          this.#metrics.totalOutputTokens += event.usage.output_tokens;
          this.#metrics.totalCost += event.cost;
        }
      }

      if (state.textParts.length > 0) {
        yield { type: "text_stream_end" };
      }
    } else {
      const data: LLMResponse = await this.#llmProvider.call(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      this.#metrics.totalInputTokens += data.usage.input_tokens;
      this.#metrics.totalOutputTokens += data.usage.output_tokens;
      this.#metrics.totalCost += data.cost;

      for (const block of data.content) {
        if (block.type === "text") {
          state.textParts.push(block.text);
          yield { type: "text", text: block.text };
        }
        if (block.type === "tool_use") {
          state.toolBlocks.push({
            id: block.id,
            name: block.name,
            input: block.input,
          });
        }
      }

      state.stopReason = data.stop_reason;
    }
  }

  /** Ejecuta las tool calls pendientes, emite eventos y llena `state.toolResults`. */
  async *#executeTools(state: TurnState): AsyncGenerator<RunnerEvent> {
    for (const block of state.toolBlocks) {
      if (block.name === "ask_user") {
        yield* this.#handleAskUser(block, state);
        continue;
      }

      this.#metrics.totalToolCalls++;

      const tool = this.#agentConfig.getTool(block.name);
      if (!tool) {
        yield* this.#handleUnknownTool(block.name, block.id, state);
        continue;
      }

      yield { type: "tool_use", name: tool.name, input: block.input };

      yield* this.#handleToolExecution(tool.name, block.id, block.input, state);
    }
  }

  // ── sub-fases de executeTools ──────────────────────────────────────

  async *#handleAskUser(
    block: { id: string; name: string; input: unknown },
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    if (!this.#onAskUser) return;

    const question =
      (block.input as { question?: string }).question ?? "¿Continuar?";
    yield { type: "ask_user", question, toolId: block.id };

    const answer = await this.#onAskUser(question);
    const output = answer || "(sin respuesta)";
    yield {
      type: "tool_result",
      output: "(confirmación recibida)",
      rawOutput: output,
    };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: block.id,
      content: output,
      is_error: false,
    });
  }

  async *#handleUnknownTool(
    name: string,
    toolId: string,
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const output = `Error: unknown tool "${name}"`;
    logger.error(output);
    yield { type: "tool_result", output };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: toolId,
      content: output,
      is_error: true,
    });
  }

  async *#handleToolExecution(
    toolName: string,
    toolId: string,
    input: unknown,
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const tool = this.#agentConfig.getTool(toolName)!;
    let output: string;
    let isError = false;
    try {
      output = tool.execute(input) as string;
    } catch (err: unknown) {
      isError = true;
      output = `Error executing tool "${toolName}": ${err instanceof Error ? err.message : String(err)}`;
      logger.error("Tool execution threw", { tool: toolName, error: output });
    }

    const shown = truncateForDisplay(output);
    const forModel = truncateForContext(output, this.#maxContextTokens);

    yield { type: "tool_result", output: shown, rawOutput: output };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: toolId,
      content: forModel,
      is_error: isError,
    });
  }

  // ── loop principal ─────────────────────────────────────────────────

  async *run(incomingContext: readonly Message[]): AsyncGenerator<RunnerEvent> {
    const workingContext = [...incomingContext];
    logger.info(`Starting runner with max steps: ${this.#maxSteps}`);

    let steps = this.#maxSteps;
    while (steps > 0) {
      if (this.#signal?.aborted) {
        this.#interrupted = true;
        logger.info("Runner interrupted by abort signal");
        yield { type: "text", text: "⏹ Interrumpido por el usuario." };
        break;
      }

      const prunedContext = pruneContext(
        workingContext,
        this.#maxContextTokens,
      );

      const state = this.#newTurnState();

      try {
        yield* this.#callLLM(prunedContext, state);
      } catch (err: unknown) {
        if (err instanceof Error && err.name === "AbortError") {
          this.#interrupted = true;
          logger.info("LLM call aborted by signal");
          yield { type: "text", text: "⏹ Interrumpido por el usuario." };
          const partialMessage: Message = {
            role: "assistant",
            content: this.#buildAssistantContent(state),
          };
          workingContext.push(partialMessage);
          yield { type: "state", message: partialMessage };
          break;
        }
        throw err;
      }

      // Agregar mensaje assistant al contexto
      const assistantMessage: Message = {
        role: "assistant",
        content: this.#buildAssistantContent(state),
      };
      workingContext.push(assistantMessage);
      yield { type: "state", message: assistantMessage };

      // Ejecutar tools
      yield* this.#executeTools(state);

      if (state.toolResults.length > 0) {
        const toolMessage: Message = {
          role: "user",
          content: state.toolResults,
        };
        workingContext.push(toolMessage);
        yield { type: "state", message: toolMessage };
      }

      if (state.stopReason === "max_tokens") {
        logger.warn("Respuesta cortada por max_tokens");
        yield {
          type: "text",
          text: "⚠ La respuesta se cortó (max_tokens). Subí el límite o pedí algo más chico.",
        };
        break;
      }

      if (state.stopReason === "end_turn") {
        logger.info("Agent finished (end_turn)");
        break;
      }

      steps--;
      if (steps === 0) {
        logger.warn(`Max steps reached (${this.#maxSteps})`);
      }
    }
  }

  getMetrics() {
    return {
      ...this.#metrics,
      durationMs: Date.now() - this.#metrics.startTime,
    };
  }

  resetMetrics() {
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }
}

export { Runner, RunnerEvent };

import { Message } from "./message.js";

// ── Truncado de outputs ──────────────────────────────────────────────────────

/** Trunca para mostrar al usuario: límite visual, no inunda la terminal. */
function truncateForDisplay(
  text: string,
  maxLines = 50,
  maxChars = 2000,
): string {
  let t = text;
  if (t.length > maxChars) {
    const half = Math.floor(maxChars / 2);
    t =
      t.slice(0, half) +
      `\n… [${t.length - maxChars} chars omitidos] …\n` +
      t.slice(-half);
  }
  const lines = t.split("\n");
  if (lines.length <= maxLines) return t;

  const keep = Math.max(1, Math.floor(maxLines / 2));
  const head = lines.slice(0, keep);
  const tail = lines.slice(-keep);
  const omitted = lines.length - keep * 2;
  const marker = `\n… [${omitted} líneas omitidas. Usá un comando más específico o read con offset/limit para ver más] …\n`;
  return [...head, marker, ...tail].join("\n");
}

/**
 * Safety net: trunca output para el LLM si supera un porcentaje del
 * presupuesto de contexto. Así un solo tool_result no satura la ventana.
 * Si el texto está dentro del límite, lo devuelve intacto.
 */
function truncateForContext(
  text: string,
  maxContextTokens: number,
  maxPercent = 0.25,
): string {
  const maxTokens = Math.floor(maxContextTokens * maxPercent);
  const textTokens = estimateTokens(text);
  if (textTokens <= maxTokens) return text;

  // Cortamos a ~maxChars equivalente
  const maxChars = maxTokens * CHARS_PER_TOKEN;
  const half = Math.floor(maxChars / 2);
  return (
    text.slice(0, half) +
    `\n… [${text.length - maxChars} chars omitidos por presupuesto] …\n` +
    text.slice(-half)
  );
}

// Mantenemos truncate como alias legacy (usan runner.ts y tests)
const truncate = truncateForDisplay;

// ── Estimación de tokens ─────────────────────────────────────────────────────

/**
 * Estimación con ~3 chars/token. Para texto natural el ratio real es ~4
 * chars/token, así que tendemos a SOBREstimar tokens, que es la dirección
 * segura: podamos de más, no de menos. Además maxContextTokens (100k)
 * está por debajo de la ventana real (~200k) como colchón extra.
 */
const CHARS_PER_TOKEN = 3;

function estimateTokens(text: string): number {
  return Math.ceil(text.length / CHARS_PER_TOKEN);
}

/**
 * Estima los tokens que ocuparía un array de mensajes al serializarse.
 * No es exacto (el formato real depende del provider: Anthropic vs OpenAI)
 * pero sirve para decidir cuántos mensajes entran en el presupuesto.
 */
function estimateMessagesTokens(messages: readonly Message[]): number {
  let total = 0;
  for (const msg of messages) {
    total += estimateTokens(JSON.stringify(msg));
  }
  return total;
}

// ── Helpers turn-aware ───────────────────────────────────────────────────────

/** ¿Este mensaje user es en realidad un bloque de tool_results? */
function isToolResultMessage(msg: Message): boolean {
  return (
    msg.role === "user" &&
    Array.isArray(msg.content) &&
    msg.content.length > 0 &&
    msg.content.some(
      (b) => b && typeof b === "object" && "type" in b && b.type === "tool_result",
    )
  );
}

/** ¿Es un punto de inicio válido para la ventana de contexto?
 *  (user de texto real, no un tool_result, no un assistant) */
function isValidWindowStart(msg: Message): boolean {
  return msg.role === "user" && !isToolResultMessage(msg);
}

// ── Poda de contexto por tokens ──────────────────────────────────────────────

/**
 * Recorta el historial desde el más antiguo hasta que el total estimado
 * de tokens entre dentro del presupuesto. Es turn-aware: nunca corta en
 * medio de un par tool_use / tool_result, ni deja un assistant como primer
 * mensaje de la ventana (lo que rompería el formato del provider).
 */
function pruneContext(
  messages: readonly Message[],
  maxTokens: number,
): Message[] {
  if (messages.length === 0) return [];

  // 1. Punto de corte tentativo por presupuesto (de más reciente a más antiguo)
  let startIdx = 0;
  let tokensUsed = 0;
  for (let i = messages.length - 1; i >= 0; i--) {
    const msgTokens = estimateTokens(JSON.stringify(messages[i]));
    if (tokensUsed + msgTokens > maxTokens && i < messages.length - 1) {
      startIdx = i + 1;
      break;
    }
    tokensUsed += msgTokens;
  }

  // 2. Avanzar startIdx hasta un inicio de turno válido (user de texto real).
  //    Descarta tool_results huérfanos y assistants al principio de la ventana.
  while (startIdx < messages.length && !isValidWindowStart(messages[startIdx])) {
    startIdx++;
  }

  // 3. Si nos pasamos de todo (turno actual gigante), devolver desde el
  //    último user válido para al menos no romper el formato.
  if (startIdx >= messages.length) {
    for (let i = messages.length - 1; i >= 0; i--) {
      if (isValidWindowStart(messages[i])) return messages.slice(i);
    }
    return [...messages]; // fallback: mandar todo y que el provider se queje
  }

  return messages.slice(startIdx);
}

export {
  truncate,
  truncateForDisplay,
  truncateForContext,
  estimateTokens,
  estimateMessagesTokens,
  pruneContext,
};

import { Message } from "./message.js";
import { writeFileSync, readFileSync, existsSync, mkdirSync, readdirSync, statSync } from "fs";
import { dirname, join, basename } from "path";
import { randomUUID } from "crypto";
import { logger } from "./logger.js";
import { estimateMessagesTokens, pruneContext } from "./context-management.js";

type SessionOptions = {
  id?: string;
  // Si se setea, la sesión se persiste en <dir>/<id>.json.
  // Sin dir, la sesión vive solo en memoria (útil para tests).
  dir?: string;
  /** Máximo de tokens de contexto a exponer al modelo (default 100000). */
  maxContextTokens?: number;
};

class Session {
  #messages: Message[];
  #id: string;
  #name: string;
  #sessionPath?: string;
  #maxContextTokens: number;
  #totalCost: number;
  #totalTokens: { input: number; output: number };

  constructor(options: SessionOptions = {}) {
    this.#id = options.id ?? randomUUID();
    this.#name = "";
    this.#messages = [];
    this.#maxContextTokens = options.maxContextTokens ?? 100_000;
    this.#totalCost = 0;
    this.#totalTokens = { input: 0, output: 0 };
    this.#sessionPath = options.dir
      ? join(options.dir, `${this.#id}.json`)
      : undefined;

    // Cargar sesión anterior si existe (al reanudar por id)
    if (this.#sessionPath && existsSync(this.#sessionPath)) {
      try {
        const data = readFileSync(this.#sessionPath, "utf-8");
        const parsed = JSON.parse(data);
        this.#messages = parsed.messages || [];
        this.#totalCost = parsed.totalCost ?? 0;
        this.#totalTokens = parsed.totalTokens ?? { input: 0, output: 0 };
        this.#name = parsed.name ?? "";
        logger.info("Session loaded from file", {
          id: this.#id,
          name: this.#name || "(sin nombre)",
          messageCount: this.#messages.length,
          totalCost: this.#totalCost,
          totalTokens: this.#totalTokens,
        });
      } catch (err: unknown) {
        logger.warn("Failed to load session file, starting fresh", {
          error: err instanceof Error ? err.message : String(err),
        });
      }
    }
  }

  get id() {
    return this.#id;
  }

  get name() {
    return this.#name;
  }

  /** Renombra la sesión y persiste el cambio */
  rename(newName: string): void {
    this.#name = newName.trim();
    this.#save();
  }

  addUserMessage(msg: string | Message["content"]) {
    this.#messages.push({
      role: "user",
      content: msg,
    } as Message);
    this.#save();
  }

  addMessage(msg: Message) {
    this.#messages.push(msg);
    this.#save();
  }

  /** Devuelve los mensajes podados por presupuesto de tokens.
   * El historial completo se guarda en disco igual. */
  get messages(): readonly Message[] {
    return pruneContext(this.#messages, this.#maxContextTokens);
  }

  /** Devuelve el historial completo sin truncar */
  get allMessages(): readonly Message[] {
    return this.#messages;
  }

  /** Tokens estimados que ocuparía el contexto actual enviado al modelo */
  get contextTokens(): number {
    return estimateMessagesTokens(this.messages);
  }

  /** Presupuesto máximo de tokens de contexto configurado */
  get maxContextTokens(): number {
    return this.#maxContextTokens;
  }

  /**
   * Acumula costo y tokens de una iteración del runner
   */
  addUsage(inputTokens: number, outputTokens: number, cost: number): void {
    this.#totalTokens = {
      input: this.#totalTokens.input + inputTokens,
      output: this.#totalTokens.output + outputTokens,
    };
    this.#totalCost += cost;
    this.#save();
  }

  get totalCost() {
    return this.#totalCost;
  }

  get totalTokens() {
    return this.#totalTokens;
  }

  /**
   * Limpia el historial de mensajes
   */
  clear(): void {
    this.#messages = [];
    this.#save();
  }

  /**
   * Devuelve información de la sesión
   */
  info(): {
    id: string;
    name: string;
    messageCount: number;
    persisted: boolean;
    path?: string;
    totalCost: number;
    totalTokens: { input: number; output: number };
  } {
    return {
      id: this.#id,
      name: this.#name,
      messageCount: this.#messages.length,
      persisted: !!this.#sessionPath,
      path: this.#sessionPath,
      totalCost: this.#totalCost,
      totalTokens: this.#totalTokens,
    };
  }

  #save(): void {
    if (!this.#sessionPath) return;

    try {
      const dir = dirname(this.#sessionPath);
      mkdirSync(dir, { recursive: true });
      writeFileSync(
        this.#sessionPath,
        JSON.stringify(
          {
            id: this.#id,
            name: this.#name || undefined,
            savedAt: new Date().toISOString(),
            messages: this.#messages,
            totalCost: this.#totalCost,
            totalTokens: this.#totalTokens,
          },
          null,
          2,
        ),
        "utf-8",
      );
    } catch (err: unknown) {
      logger.error("Failed to save session", { error: err instanceof Error ? err.message : String(err) });
    }
  }

  /**
   * Lista sesiones persistidas en un directorio, ordenadas por fecha de modificación (más reciente primero).
   * Devuelve info resumida: id, fecha, cantidad de mensajes, costo y tokens.
   */
  static listSessions(dir: string): Array<{
    id: string;
    name: string;
    savedAt: string;
    messageCount: number;
    totalCost: number;
    totalTokens: { input: number; output: number };
  }> {
    const results: Array<{
      id: string;
      name: string;
      savedAt: string;
      messageCount: number;
      totalCost: number;
      totalTokens: { input: number; output: number };
    }> = [];

    try {
      if (!existsSync(dir)) return results;

      const files = readdirSync(dir)
        .filter((f) => f.endsWith(".json"))
        .map((f) => join(dir, f))
        .sort((a, b) => statSync(b).mtimeMs - statSync(a).mtimeMs);

      for (const file of files) {
        try {
          const data = readFileSync(file, "utf-8");
          const parsed = JSON.parse(data);
          results.push({
            id: parsed.id ?? basename(file, ".json"),
            name: parsed.name ?? "",
            savedAt: parsed.savedAt ?? "",
            messageCount: Array.isArray(parsed.messages) ? parsed.messages.length : 0,
            totalCost: parsed.totalCost ?? 0,
            totalTokens: parsed.totalTokens ?? { input: 0, output: 0 },
          });
        } catch {
          // Archivo corrupto, lo salteamos
          logger.warn("Skipping corrupt session file", { file });
        }
      }
    } catch (err: unknown) {
      logger.error("Failed to list sessions", { error: err instanceof Error ? err.message : String(err) });
    }

    return results;
  }
}

export { Session };

type ToolMessage = {
  type: "tool_result";
  tool_use_id: string;
  content: unknown;
  is_error: boolean;
};

type ToolUseMessage = {
  type: "tool_use";
  id: string;
  name: string;
  input: unknown;
};

type TextMessage =
  | {
      type: "text";
      text: string;
    }
  | string;

type ImageMessage = {
  type: "image";
  source: {
    type: "base64";
    media_type: string;
    data: string;
  };
};

type MessageContent = ToolMessage | ToolUseMessage | TextMessage | ImageMessage;

type Message = {
  role: "user" | "assistant";
  content: MessageContent | MessageContent[];
};

export { ImageMessage, Message, TextMessage, ToolMessage, ToolUseMessage };

import { readFileSync } from "fs";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

type ReadInput = { path: string; offset?: number; limit?: number };

export class ReadTool extends Tool<ReadInput, string> {
  constructor() {
    super({
      name: "read",
      description: "Devuelve el contenido de un archivo",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a leer" },
          offset: {
            type: "number",
            description: "Línea desde la que empezar (1-indexed, opcional)",
          },
          limit: {
            type: "number",
            description: "Máximo de líneas a leer (opcional)",
          },
        },
        required: ["path"],
      },
    });
  }

  execute(input: unknown): string {
    try {
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path");
      }

      const { path, offset, limit } = input as ReadInput;

      if (typeof path !== "string" || !path.trim()) {
        throw new Error("path must be a non-empty string");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked read of env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Reading file", { path, offset, limit });
      const content = readFileSync(path, "utf-8");

      // sin offset/limit: devolvemos el archivo entero
      if (offset === undefined && limit === undefined) {
        logger.info("File read successfully", { path, lines: content.split("\n").length });
        return content;
      }

      const lines = content.split("\n");
      const start = offset ? offset - 1 : 0; // offset es 1-indexed
      const end = limit ? start + limit : lines.length;
      const result = lines.slice(start, end).join("\n");
      logger.info("File slice read successfully", { path, start, end });
      return result;
    } catch (err: unknown) {
      const pathName = input !== null && typeof input === "object" && "path" in (input as object)
        ? String((input as ReadInput).path)
        : String(input);
      const errorMsg = `Error reading ${pathName}: ${err instanceof Error ? err.message : String(err)}`;
      logger.error(errorMsg);
      return errorMsg;
    }
  }
}

import { Tool } from "./tools/tool.js";

type AgentConfigConstructorProps = {
  systemPrompt: string;
  model: string;
  maxTokens: number;
};

class AgentConfig {
  #systemPrompt: string;
  #model: string;
  #max_tokens: number;
  #tools: Record<string, Tool<unknown, unknown>>;

  constructor({ model, maxTokens, systemPrompt }: AgentConfigConstructorProps) {
    this.#systemPrompt = systemPrompt;
    this.#model = model;
    this.#max_tokens = maxTokens;
    this.#tools = {};
  }

  addTool(tool: Tool<unknown, unknown>): AgentConfig {
    this.#tools = { ...this.#tools, [tool.name]: tool };
    return this;
  }

  getTool(name: string) {
    return this.#tools[name];
  }

  get systemPrompt() {
    return this.#systemPrompt;
  }

  get model() {
    return this.#model;
  }

  get maxTokens() {
    return this.#max_tokens;
  }

  tools() {
    return this.#tools;
  }

  toJSON() {
    return {
      model: this.#model,
      max_tokens: this.#max_tokens,
      tools: Object.values(this.#tools).map((t) => t.toJSON()),
    };
  }
}

