import { describe, it, expect, beforeEach } from "vitest";
import { Session } from "../session.js";
import { MessageFactory } from "./factories/message.factory.js";

describe("Session", () => {
  let session: Session;

  beforeEach(() => {
    session = new Session();
  });

  it("should initialize with empty messages", () => {
    expect(session.messages).toHaveLength(0);
  });

  it("should add user messages", () => {
    session.addUserMessage("Hello");
    expect(session.messages).toHaveLength(1);
    expect(session.messages[0].role).toBe("user");
    expect(session.messages[0].content).toBe("Hello");
  });

  it("should add multiple user messages", () => {
    session.addUserMessage("First");
    session.addUserMessage("Second");
    expect(session.messages).toHaveLength(2);
    expect(session.messages[0].content).toBe("First");
    expect(session.messages[1].content).toBe("Second");
  });

  it("should add assistant messages", () => {
    const assistantMsg = MessageFactory.createAssistantMessage("Response");
    session.addMessage(assistantMsg);
    expect(session.messages).toHaveLength(1);
    expect(session.messages[0].role).toBe("assistant");
  });

  it("should maintain message order", () => {
    session.addUserMessage("User message");
    const assistantMsg = MessageFactory.createAssistantMessage();
    session.addMessage(assistantMsg);
    session.addUserMessage("Another user message");

    expect(session.messages).toHaveLength(3);
    expect(session.messages[0].role).toBe("user");
    expect(session.messages[1].role).toBe("assistant");
    expect(session.messages[2].role).toBe("user");
  });

  it("should return a copy of messages array", () => {
    session.addUserMessage("Test");
    const messages1 = session.messages;
    const messages2 = session.messages;
    expect(messages1).toEqual(messages2);
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import { Runner } from "../runner.js";
import { AgentConfig } from "../agent-config.js";
import { LLMProvider, LLMResponse, StreamEvent } from "../providers/llm-provider.js";
import { BashTool } from "../tools/bash.js";
import { ReadTool } from "../tools/read.js";
import { Message } from "../message.js";

// ── Mock LLM Provider ────────────────────────────────────────────────────────

class MockLLMProvider extends LLMProvider {
  #responses: LLMResponse[];
  #callCount = 0;

  constructor(responses: LLMResponse[]) {
    super({ apiKey: "mock-key", url: "http://mock" });
    this.#responses = responses;
  }

  async call(_messages: Message[], _agent: AgentConfig): Promise<LLMResponse> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;
    return resp;
  }

  async *callStream(_messages: Message[], _agent: AgentConfig): AsyncGenerator<StreamEvent> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;

    for (const block of resp.content) {
      if (block.type === "text") {
        yield { type: "text", text: block.text };
      }
      if (block.type === "tool_use") {
        yield { type: "tool_use", id: block.id, name: block.name, input: block.input };
      }
    }

    yield {
      type: "done",
      stop_reason: resp.stop_reason,
      usage: resp.usage,
      cost: resp.cost,
    };
  }
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function mockAgent(): AgentConfig {
  const agent = new AgentConfig({
    systemPrompt: "Test",
    model: "claude-haiku-4-5-20251001",
    maxTokens: 1024,
  });
  agent.addTool(new BashTool());
  agent.addTool(new ReadTool());
  return agent;
}

function textResponse(text: string): LLMResponse {
  return {
    content: [{ type: "text", text }],
    stop_reason: "end_turn",
    usage: { input_tokens: 10, output_tokens: 5 },
    cost: 0.0001,
  };
}

function toolUseResponse(
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: toolCalls.map((tc) => ({
      type: "tool_use" as const,
      ...tc,
    })),
    stop_reason: "tool_use",
    usage: { input_tokens: 20, output_tokens: 10 },
    cost: 0.0002,
  };
}

function mixedResponse(
  text: string,
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: [
      { type: "text" as const, text },
      ...toolCalls.map((tc) => ({ type: "tool_use" as const, ...tc })),
    ],
    stop_reason: "tool_use",
    usage: { input_tokens: 30, output_tokens: 15 },
    cost: 0.0003,
  };
}

async function collectEvents(runner: Runner, context: Message[]): Promise<Array<{ type: string; name?: string }>> {
  const events: Array<{ type: string; name?: string }> = [];
  for await (const event of runner.run(context)) {
    events.push({ type: event.type, name: "name" in event ? (event as { name: string }).name : undefined });
  }
  return events;
}

// ── Tests ────────────────────────────────────────────────────────────────────

describe("Runner", () => {
  describe("single text response", () => {
    it("should emit text and state events for a simple text response", async () => {
      const provider = new MockLLMProvider([textResponse("Hello!")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "Hi" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "text_stream_end")).toBe(true);
      expect(events.some((e) => e.type === "state")).toBe(true);
    });

    it("should not emit tool_use events for text-only response", async () => {
      const provider = new MockLLMProvider([textResponse("Done")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(false);
      expect(events.some((e) => e.type === "tool_result")).toBe(false);
    });
  });

  describe("tool use response", () => {
    it("should execute tool and emit tool_result", async () => {
      // 1st: tool_use, 2nd: end_turn
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo hello" } }]),
        textResponse("Tool executed."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run echo" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle unknown tool gracefully", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "nonexistent_tool", input: {} }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "use unknown tool" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle mixed text + tool_use", async () => {
      const provider = new MockLLMProvider([
        mixedResponse("Let me check...", [
          { id: "t1", name: "bash", input: { command: "pwd" } },
        ]),
        textResponse("All done."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "where am I?" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });
  });

  describe("max_tokens stop reason", () => {
    it("should emit warning text on max_tokens", async () => {
      const provider = new MockLLMProvider([{
        content: [{ type: "text", text: "Partial..." }],
        stop_reason: "max_tokens",
        usage: { input_tokens: 10, output_tokens: 5 },
        cost: 0.0001,
      }]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "big task" }];

      const events: string[] = [];
      for await (const event of runner.run(context)) {
        if (event.type === "text") {
          events.push(event.text);
        }
      }
      const warning = events.find((t) => t.includes("cortó"));
      expect(warning).toBeDefined();
    });
  });

  describe("metrics", () => {
    it("should accumulate token usage and cost", async () => {
      const provider = new MockLLMProvider([
        textResponse("First"),
        textResponse("Second"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "multi" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBeGreaterThan(0);
      expect(metrics.totalOutputTokens).toBeGreaterThan(0);
      expect(metrics.totalCost).toBeGreaterThan(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.durationMs).toBeGreaterThanOrEqual(0);
    });

    it("should count tool calls", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo a" } }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run cmd" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      expect(runner.getMetrics().totalToolCalls).toBe(1);
    });
  });

  describe("max steps", () => {
    it("should stop after maxSteps", async () => {
      // Cada respuesta pide tool_use -> el loop consumiría steps hasta el límite
      const responses: LLMResponse[] = [];
      for (let i = 0; i < 20; i++) {
        responses.push(
          toolUseResponse([{ id: `t${i}`, name: "bash", input: { command: "echo x" } }]),
        );
      }
      const provider = new MockLLMProvider(responses);
      const runner = new Runner({
        llmProvider: provider,
        agentConfig: mockAgent(),
        maxSteps: 3,
      });
      const context: Message[] = [{ role: "user", content: "loop" }];

      let toolUseCount = 0;
      for await (const event of runner.run(context)) {
        if (event.type === "tool_use") toolUseCount++;
      }

      // Con maxSteps=3, el loop hace 3 iteraciones de tool_use
      expect(toolUseCount).toBeLessThanOrEqual(3);
    });
  });

  describe("resetMetrics", () => {
    it("should reset all metrics to zero", async () => {
      const provider = new MockLLMProvider([textResponse("Hi")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      runner.resetMetrics();
      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBe(0);
      expect(metrics.totalOutputTokens).toBe(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.totalCost).toBe(0);
    });
  });
});

import { describe, it, expect } from "vitest";
import {
  truncate,
  estimateTokens,
  estimateMessagesTokens,
  pruneContext,
} from "../context-management.js";
import { Message } from "../message.js";

// ── Helpers para construir mensajes ──────────────────────────────────────────

function userText(text: string): Message {
  return { role: "user", content: text };
}

function assistantText(text: string): Message {
  return { role: "assistant", content: text };
}

function assistantToolUse(blocks: Array<{ id: string; name: string; input: unknown }>): Message {
  return {
    role: "assistant",
    content: blocks.map((b) => ({ type: "tool_use" as const, ...b })),
  };
}

function userToolResult(results: Array<{ tool_use_id: string; content: string }>): Message {
  return {
    role: "user",
    content: results.map((r) => ({
      type: "tool_result" as const,
      ...r,
      is_error: false,
    })),
  };
}

// ── truncate ─────────────────────────────────────────────────────────────────

describe("truncate", () => {
  it("no trunca texto corto", () => {
    const text = "hola\nchau";
    expect(truncate(text, 10)).toBe(text);
  });

  it("trunca cuando excede maxLines", () => {
    const lines = Array.from({ length: 100 }, (_, i) => `linea ${i}`);
    const text = lines.join("\n");
    const result = truncate(text, 20);
    expect(result).toContain("líneas omitidas");
    const resultLines = result.split("\n");
    expect(resultLines.length).toBeLessThanOrEqual(23); // 10 head + \n + marker + \n + \n + 10 tail
  });

  it("conserva primeras y últimas líneas", () => {
    const lines = Array.from({ length: 100 }, (_, i) => `linea ${i}`);
    const text = lines.join("\n");
    const result = truncate(text, 20);
    expect(result).toContain("linea 0");
    expect(result).toContain("linea 99");
  });
});

// ── estimateTokens ───────────────────────────────────────────────────────────

describe("estimateTokens", () => {
  it("estima ~3 chars por token", () => {
    expect(estimateTokens("abc")).toBe(1);
    expect(estimateTokens("abcd")).toBe(2); // ceil(4/3) = 2
  });

  it("devuelve 0 para string vacío", () => {
    expect(estimateTokens("")).toBe(0);
  });
});

// ── estimateMessagesTokens ───────────────────────────────────────────────────

describe("estimateMessagesTokens", () => {
  it("acumula tokens de varios mensajes", () => {
    const msgs: Message[] = [
      userText("hola"),
      assistantText("qué tal"),
    ];
    const total = estimateMessagesTokens(msgs);
    expect(total).toBeGreaterThan(0);
  });

  it("devuelve 0 para array vacío", () => {
    expect(estimateMessagesTokens([])).toBe(0);
  });
});

// ── pruneContext (turn-aware) ────────────────────────────────────────────────

describe("pruneContext", () => {
  it("devuelve array vacío si no hay mensajes", () => {
    expect(pruneContext([], 1000)).toEqual([]);
  });

  it("devuelve todos los mensajes si entran en el presupuesto", () => {
    const msgs: Message[] = [
      userText("hola"),
      assistantText("qué tal"),
    ];
    const result = pruneContext(msgs, 1_000_000);
    expect(result).toEqual(msgs);
  });

  it("recorta desde el más antiguo cuando excede presupuesto", () => {
    // Crear varios turnos user/assistant largos
    const msgs: Message[] = [];
    for (let i = 0; i < 20; i++) {
      msgs.push(userText(`mensaje del usuario numero ${i} con algo de relleno`));
      msgs.push(assistantText(`respuesta del asistente numero ${i} con mas relleno`));
    }

    const allTokens = estimateMessagesTokens(msgs);
    const budget = Math.floor(allTokens * 0.3); // solo 30% entra
    const result = pruneContext(msgs, budget);

    // Debe devolver menos mensajes
    expect(result.length).toBeLessThan(msgs.length);
    // El primer mensaje debe ser un user de texto
    expect(result[0].role).toBe("user");
    // El último mensaje debe ser el último del original
    expect(result[result.length - 1]).toEqual(msgs[msgs.length - 1]);
  });

  it("nunca deja un assistant como primer mensaje", () => {
    // Si el corte deja un assistant al principio, debe avanzar al siguiente user
    const msgs: Message[] = [
      userText("turno 1"),
      assistantText("respuesta 1"),
      userText("turno 2"),
      assistantText("respuesta 2"),
      userText("turno 3"),
      assistantText("respuesta 3"),
    ];

    // Budget tan chico que solo entren los últimos mensajes
    const lastTwo = msgs.slice(-2);
    const budget = estimateMessagesTokens(lastTwo) + 10; // solo entran los últimos 2

    const result = pruneContext(msgs, budget);

    // El primer mensaje NO puede ser assistant
    expect(result[0].role).toBe("user");
    // Si budget daba para [user("turno 3"), assistant("respuesta 3")], está bien
    // Si daba para [assistant("respuesta 2"), user("turno 3"), assistant("respuesta 3")],
    // debe haber avanzado para que el primero sea user("turno 3")
  });

  it("evita tool_results huérfanos al principio", () => {
    // Simula: user, assistant(tool_use), user(tool_results), assistant, user
    // Si el corte cae entre assistant(tool_use) y user(tool_results),
    // debe avanzar para incluir el tool_use o descartar el tool_result
    const msgs: Message[] = [
      userText("hacé algo"),
      assistantToolUse([{ id: "t1", name: "read", input: { path: "a.ts" } }]),
      userToolResult([{ tool_use_id: "t1", content: "contenido largo ".repeat(500) }]),
      assistantText("listo, leí el archivo"),
      userText("gracias"),
    ];

    // Budget: que entre el último user + assistant, pero el tool_result es enorme
    // y fuerza el corte en medio del turno tool
    const budget = estimateMessagesTokens([
      assistantText("listo, leí el archivo"),
      userText("gracias"),
    ]) + 50;

    const result = pruneContext(msgs, budget);

    // No debe haber tool_results huérfanos al inicio
    const first = result[0];
    const isToolResult =
      first.role === "user" &&
      Array.isArray(first.content) &&
      first.content.some(
        (b: unknown) => b && typeof b === "object" && (b as Record<string, unknown>).type === "tool_result",
      );
    expect(isToolResult).toBe(false);

    // El primer mensaje debe ser un user de texto
    expect(first.role).toBe("user");
  });

  it("maneja turno gigante (único turno > budget)", () => {
    // Un solo turno con tool_results gigantes que exceden el budget
    const msgs: Message[] = [
      userText("hacé algo con archivos grandes"),
      assistantToolUse([
        { id: "t1", name: "read", input: { path: "big.ts" } },
        { id: "t2", name: "read", input: { path: "huge.ts" } },
      ]),
      userToolResult([
        { tool_use_id: "t1", content: "x".repeat(50_000) },
        { tool_use_id: "t2", content: "y".repeat(50_000) },
      ]),
      assistantText("listo"),
      userText("gracias"),
    ];

    // Budget muy chico, ni el turno actual entra completo
    const result = pruneContext(msgs, 100);

    // Al menos debe devolver algo que empiece con user de texto
    expect(result.length).toBeGreaterThan(0);
    expect(result[0].role).toBe("user");

    // No tool_results huérfanos
    const first = result[0];
    const isToolResult =
      first.role === "user" &&
      Array.isArray(first.content) &&
      first.content.some(
        (b: unknown) => b && typeof b === "object" && (b as Record<string, unknown>).type === "tool_result",
      );
    expect(isToolResult).toBe(false);
  });

  it("conserva el último mensaje (el input del usuario)", () => {
    const msgs: Message[] = [
      userText("turno 1"),
      assistantText("respuesta 1"),
      userText("turno 2"),
      assistantText("respuesta 2"),
      userText("turno 3"),
    ];

    const budget = estimateMessagesTokens([userText("turno 3")]) + 5;
    const result = pruneContext(msgs, budget);

    expect(result.length).toBeGreaterThan(0);
    expect(result[result.length - 1]).toEqual(userText("turno 3"));
  });

  it("no rompe con mensajes user que tienen content string", () => {
    const msgs: Message[] = [
      userText("hola"),
      assistantText("respuesta"),
    ];

    // Budget amplio: todo entra
    const result = pruneContext(msgs, 1_000_000);
    expect(result).toEqual(msgs);
  });

  it("no rompe con content mixto (string en vez de array)", () => {
    // Un user con content string simple
    const msgs: Message[] = [
      { role: "user", content: "texto simple" },
      assistantText("respuesta"),
    ];
    const result = pruneContext(msgs, 1_000_000);
    expect(result).toEqual(msgs);
  });
});

